/bin/zsh -lc "python - <<'PY'
import csv,json,math

def round10(x):
    return int(math.floor(x/10 + 0.5) * 10)

factors={'A':1.5,'B':1.2,'C':1.0}
rows=[]
with open('input.csv', newline='') as f:
    for r in csv.DictReader(f):
        daily=int(r['daily_sales']); lead=int(r['lead_time']); stock=int(r['current_stock'])
        min_order=int(r['min_order']); month=int(r['month']); cat=r['category']
        if r['supplier']=='unavailable':
            decision='BACKORDER'; qty=0
        elif stock <= daily*lead*factors[cat]:
            decision='REORDER'
            qty=round10(max(min_order, math.ceil(daily*30-stock)))
            if month in {11,12,1} and cat=='A':
                qty=round10(qty*1.5)
        else:
            decision='HOLD'; qty=0
        rows.append({'id':r['id'],'decision':decision,'order_qty':qty})
print(json.dumps(rows, ensure_ascii=False, indent=2))
PY"

